{"action":"write","content":"const http = require('http');
const os = require('os');
const fs = require('fs');
const path = require('path');

const PORT = process.env.PORT || 3000;

// Store previous CPU times for delta calculation
let previousCpuTimes = null;

function getCpuUsagePercent() {
  const cpus = os.cpus();
  let totalIdle = 0;
  let totalTick = 0;

  for (const cpu of cpus) {
    for (const type in cpu.times) {
      totalTick += cpu.times[type];
    }
    totalIdle += cpu.times.idle;
  }

  const current = { idle: totalIdle, tick: totalTick };

  if (!previousCpuTimes) {
    previousCpuTimes = current;
    return 0; // First call baseline
  }

  const idleDiff = current.idle - previousCpuTimes.idle;
  const tickDiff = current.tick - previousCpuTimes.tick;
  previousCpuTimes = current;

  if (tickDiff === 0) return 0;

  const percent = 100 - Math.round((100 * idleDiff) / tickDiff);
  return Math.max(0, Math.min(100, percent));
}

function getMemoryMetrics() {
  const total = os.totalmem();
  const free = os.freemem();
  const used = total - free;
  const percentUsed = Math.round((used / total) * 100);

  return {
    total,
    free,
    used,
    percentUsed
  };
}

function getMetrics() {
  const cpuPercent = getCpuUsagePercent();
  const memory = getMemoryMetrics();

  return {
    timestamp: new Date().toISOString(),
    cpu: {
      percent: cpuPercent
    },
    memory: {
      total: memory.total,
      free: memory.free,
      used: memory.used,
      percentUsed: memory.percentUsed
    }
  };
}

const server = http.createServer((req, res) => {
  const url = req.url;
  const method = req.method;

  // Enable CORS for local development
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  if (url === '/api/metrics' && method === 'GET') {
    const metrics = getMetrics();
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(metrics));
    return;
  }

  if (url === '/' && method === 'GET') {
    const htmlPath = path.join(__dirname, 'public', 'index.html');
    fs.readFile(htmlPath, (err, data) => {
      if (err) {
        res.writeHead(500, { 'Content-Type': 'text/plain' });
        res.end('Error loading dashboard');
        return;
      }
      res.writeHead(200, { 'Content-Type': 'text/html' });
      res.end(data);
    });
    return;
  }

  res.writeHead(404, { 'Content-Type': 'text/plain' });
  res.end('Not Found');
});

server.listen(PORT, () => {
  console.log(`System Monitor Dashboard running at http://localhost:${PORT}`);
});
